import React, { useState, useEffect, useRef } from 'react';
import {
  Plus,
  MoreHorizontal,
  Settings,
  Mail,
  Video,
  Box,
  CheckSquare,
  Clipboard,
  X,
  ChevronDown
} from 'lucide-react';

interface Integration {
  id: string;
  name: string;
  description: string;
  isEnabled: boolean;
  icon: React.ReactNode;
  iconBg: string;
}

const Integrations: React.FC = () => {
  const [integrations, setIntegrations] = useState<Integration[]>([
    { id: '1', name: 'Mailchimp', description: '마케팅 이메일 전송 및 캠페인 관리를 자동화하기 위해 Mailchimp를 연결하세요.', isEnabled: true, icon: <span className="text-2xl">🐵</span>, iconBg: 'bg-white' },
    { id: '2', name: 'Google Meet', description: '원활한 화상 회의 진행을 위해 Google Meet 계정을 연동하세요.', isEnabled: false, icon: <Video className="w-6 h-6 text-emerald-500" />, iconBg: 'bg-white' },
    { id: '3', name: 'Zoom', description: '원격 회의 및 팀 협업을 위해 Zoom을 통합하세요.', isEnabled: false, icon: <Video className="w-6 h-6 text-blue-500" />, iconBg: 'bg-blue-500' },
    { id: '4', name: 'Loom', description: '영상 메시지를 쉽게 녹화하고 공유, 관리할 수 있도록 Loom을 연동하세요.', isEnabled: false, icon: <Box className="w-6 h-6 text-indigo-500" />, iconBg: 'bg-white' },
    { id: '5', name: 'Linear', description: '팀의 이슈를 관리하고 진행 상황을 추적하기 위해 Linear를 연결하세요.', isEnabled: false, icon: <CheckSquare className="w-6 h-6 text-indigo-600" />, iconBg: 'bg-indigo-600' },
    { id: '6', name: 'Gmail', description: '워크스페이스에서 직접 이메일을 주고받으며 관리하도록 Gmail을 연동하세요.', isEnabled: false, icon: <Mail className="w-6 h-6 text-red-500" />, iconBg: 'bg-white' },
    { id: '7', name: 'Trello', description: '어디서든 일정을 기록하고 칸반 보드로 시각적으로 관리하세요.', isEnabled: false, icon: <Clipboard className="w-6 h-6 text-blue-600" />, iconBg: 'bg-blue-600' },
    { id: '8', name: 'Notion', description: '팀의 지식을 기록, 공유하고 프로젝트를 함께 체계적으로 구축하세요.', isEnabled: false, icon: <CheckSquare className="w-6 h-6 text-black" />, iconBg: 'bg-white' },
    { id: '9', name: 'Jira', description: '팀 전체가 이슈를 추적하고 프로젝트 진행 상황을 쉽게 확인할 수 있습니다.', isEnabled: false, icon: <Box className="w-6 h-6 text-blue-500" />, iconBg: 'bg-white' }
  ]);

  const [activeModal, setActiveModal] = useState<'none' | 'new' | 'settings' | 'details' | 'remove'>('none');
  const [selectedApp, setSelectedApp] = useState<Integration | null>(null);
  const [dropdownOpenId, setDropdownOpenId] = useState<string | null>(null);
  const [newAppName, setNewAppName] = useState('');
  const dropdownRef = useRef<HTMLDivElement>(null);

  const toggleIntegration = (id: string) => {
    setIntegrations(prev => prev.map(item => item.id === id ? { ...item, isEnabled: !item.isEnabled } : item));
  };

  return (
    <div className="space-y-8 pb-10">
      <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-6">
        {integrations.map((item) => (
          <div key={item.id} className="bg-white dark:bg-[#1A222C] rounded-xl border border-slate-100 dark:border-slate-800 shadow-sm overflow-hidden flex flex-col group hover:shadow-md transition-all">
            <div className="p-6 flex-1">
              <div className="flex justify-between items-start mb-4">
                <div className={`w-12 h-12 rounded-xl flex items-center justify-center border border-slate-50 dark:border-slate-800 ${item.id === '3' || item.id === '5' || item.id === '7' ? item.iconBg : 'bg-white dark:bg-slate-800'} shadow-sm`}>
                  {item.icon}
                </div>
                <button className="text-slate-400 hover:text-slate-600 dark:hover:text-white transition-colors">
                  <MoreHorizontal className="w-5 h-5" />
                </button>
              </div>
              <h3 className="text-lg font-bold text-slate-800 dark:text-white mb-2">{item.name}</h3>
              <p className="text-sm text-slate-500 dark:text-slate-400 leading-relaxed">{item.description}</p>
            </div>
            <div className="px-6 py-4 border-t border-slate-50 dark:border-slate-800 flex items-center justify-between bg-slate-50/30 dark:bg-slate-800/20">
              <div className="flex items-center gap-2">
                <button className="w-9 h-9 rounded-lg border border-slate-200 dark:border-slate-700 flex items-center justify-center text-slate-500 dark:text-slate-400 hover:bg-white dark:hover:bg-slate-800 hover:text-indigo-600 transition-all">
                  <Settings className="w-4 h-4" />
                </button>
                <button className="px-4 py-2 text-xs font-bold text-slate-700 dark:text-slate-300 border border-slate-200 dark:border-slate-700 rounded-lg hover:bg-white dark:hover:bg-slate-800 transition-all">상세 정보</button>
              </div>
              <button onClick={() => toggleIntegration(item.id)} className={`relative inline-flex h-6 w-11 shrink-0 cursor-pointer rounded-full border-2 border-transparent transition-colors duration-200 ease-in-out ${item.isEnabled ? 'bg-indigo-600' : 'bg-slate-200 dark:bg-slate-700'}`}>
                <span className={`pointer-events-none inline-block h-5 w-5 transform rounded-full bg-white shadow ring-0 transition duration-200 ease-in-out ${item.isEnabled ? 'translate-x-5' : 'translate-x-0'}`} />
              </button>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

export default Integrations;
